import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"温榆河公园","description":"","frontmatter":{},"headers":[],"relativePath":"parks/wenyuhe.md","filePath":"parks/wenyuhe.md","lastUpdated":1784773307000}'),n={name:"parks/wenyuhe.md"};function d(s,t,i,o,g,h){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="温榆河公园" tabindex="-1">温榆河公园 <a class="header-anchor" href="#温榆河公园" aria-label="Permalink to &quot;温榆河公园&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1583977393611-885b3e5cc701?w=1200" alt="温榆河公园"></p><blockquote><p>&quot;城市绿肺，生态家园。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>温榆河公园位于北京市朝阳区，是北京市最大的城市公园之一。公园占地面积约30平方公里，是北京市重要的生态涵养区。温榆河公园以其优美的自然风光和丰富的生态资源闻名，是市民休闲娱乐的好去处。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">全天开放</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">半天至一天</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜，春夏最佳</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁14号线来广营站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市朝阳区温榆河地区</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="规划建设" tabindex="-1">规划建设 <a class="header-anchor" href="#规划建设" aria-label="Permalink to &quot;规划建设&quot;">​</a></h3><p>温榆河公园是北京市近年来重点建设的生态公园之一。公园的建设旨在改善城市生态环境，提升市民生活质量。</p><h4 id="发展历程" tabindex="-1">发展历程 <a class="header-anchor" href="#发展历程" aria-label="Permalink to &quot;发展历程&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">时间</th><th style="text-align:left;">事件</th></tr></thead><tbody><tr><td style="text-align:left;">2018年</td><td style="text-align:left;">温榆河公园开始规划</td></tr><tr><td style="text-align:left;">2020年</td><td style="text-align:left;">温榆河公园一期建成开放</td></tr><tr><td style="text-align:left;">2022年</td><td style="text-align:left;">温榆河公园二期建成开放</td></tr><tr><td style="text-align:left;">2024年</td><td style="text-align:left;">温榆河公园全面开放</td></tr></tbody></table><h2 id="主要景点" tabindex="-1">主要景点 <a class="header-anchor" href="#主要景点" aria-label="Permalink to &quot;主要景点&quot;">​</a></h2><h3 id="生态景观区" tabindex="-1">生态景观区 <a class="header-anchor" href="#生态景观区" aria-label="Permalink to &quot;生态景观区&quot;">​</a></h3><p>温榆河公园以其优美的生态景观闻名，是北京市重要的生态涵养区。</p><h4 id="生态景观" tabindex="-1">生态景观 <a class="header-anchor" href="#生态景观" aria-label="Permalink to &quot;生态景观&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">景观</th><th style="text-align:left;">特色</th><th style="text-align:left;">最佳观赏期</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>湿地景观</strong></td><td style="text-align:left;">自然湿地</td><td style="text-align:left;">四季</td></tr><tr><td style="text-align:left;"><strong>森林景观</strong></td><td style="text-align:left;">人工林</td><td style="text-align:left;">四季</td></tr><tr><td style="text-align:left;"><strong>花海景观</strong></td><td style="text-align:left;">各种花卉</td><td style="text-align:left;">春夏</td></tr><tr><td style="text-align:left;"><strong>草坪景观</strong></td><td style="text-align:left;">大面积草坪</td><td style="text-align:left;">春夏</td></tr></tbody></table><h3 id="休闲娱乐区" tabindex="-1">休闲娱乐区 <a class="header-anchor" href="#休闲娱乐区" aria-label="Permalink to &quot;休闲娱乐区&quot;">​</a></h3><p>温榆河公园设有多个休闲娱乐区，满足市民的各种休闲需求。</p><h4 id="休闲设施" tabindex="-1">休闲设施 <a class="header-anchor" href="#休闲设施" aria-label="Permalink to &quot;休闲设施&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">设施</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>儿童游乐场</strong></td><td style="text-align:left;">儿童游乐设施</td></tr><tr><td style="text-align:left;"><strong>健身步道</strong></td><td style="text-align:left;">健身步道</td></tr><tr><td style="text-align:left;"><strong>自行车道</strong></td><td style="text-align:left;">自行车道</td></tr><tr><td style="text-align:left;"><strong>露营区</strong></td><td style="text-align:left;">露营设施</td></tr><tr><td style="text-align:left;"><strong>烧烤区</strong></td><td style="text-align:left;">烧烤设施</td></tr></tbody></table><h3 id="文化景观区" tabindex="-1">文化景观区 <a class="header-anchor" href="#文化景观区" aria-label="Permalink to &quot;文化景观区&quot;">​</a></h3><p>温榆河公园设有多个文化景观区，展示了北京的文化底蕴。</p><h4 id="文化景观" tabindex="-1">文化景观 <a class="header-anchor" href="#文化景观" aria-label="Permalink to &quot;文化景观&quot;">​</a></h4><ul><li><strong>文化广场</strong>：文化活动和演出</li><li><strong>雕塑园</strong>：各种雕塑作品</li><li><strong>文化长廊</strong>：展示北京文化</li></ul><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>精华路线（约4小时）</strong>：</p><p>入口 → 生态景观区 → 休闲娱乐区 → 文化景观区 → 出口</p><p><strong>亲子路线（约半天）</strong>：</p><p>入口 → 儿童游乐场 → 花海景观 → 草坪景观 → 出口</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>最佳时间</strong>：春夏季节是最佳观赏期</li><li><strong>露营注意</strong>：露营需提前了解相关规定</li><li><strong>拍照位置</strong>：花海、湿地、森林都是绝佳拍照点</li><li><strong>餐饮推荐</strong>：园内有餐饮设施，也可以自带食物</li><li><strong>交通建议</strong>：建议自驾或乘坐公共交通</li></ol><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地铁</strong></td><td style="text-align:left;">14号线来广营站，换乘公交</td></tr><tr><td style="text-align:left;"><strong>公交</strong></td><td style="text-align:left;">快速公交3线、专116路温榆河公园站</td></tr><tr><td style="text-align:left;"><strong>打车</strong></td><td style="text-align:left;">定位&quot;温榆河公园&quot;即可</td></tr><tr><td style="text-align:left;"><strong>自驾</strong></td><td style="text-align:left;">公园有停车场</td></tr></tbody></table><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">奥林匹克森林公园</td><td style="text-align:center;">约5公里</td><td style="text-align:left;">城市公园</td></tr><tr><td style="text-align:left;">朝阳公园</td><td style="text-align:center;">约5公里</td><td style="text-align:left;">城市公园</td></tr><tr><td style="text-align:left;">北京植物园</td><td style="text-align:center;">约10公里</td><td style="text-align:left;">植物园</td></tr><tr><td style="text-align:left;">香山公园</td><td style="text-align:center;">约15公里</td><td style="text-align:left;">山林公园</td></tr></tbody></table><hr><p><strong>📍 地址</strong>：北京市朝阳区温榆河地区 <strong>🚇 地铁</strong>：14号线来广营站，换乘公交 <strong>📞 电话</strong>：010-64756666</p><p><strong>💡 Tips</strong>：温榆河公园面积很大，建议穿舒适的鞋子。春夏季节是最佳观赏期，建议早去。</p>',40)])])}const y=e(n,[["render",d]]);export{f as __pageData,y as default};
